1700	        ch_0_out_1 = MIN(ch_0_out_1, activation_max);
1701	        *out_1++ = (q7_t)ch_0_out_1;
1702	        out_mult++;
1703	        out_shift++;
1704	    }
1705	
1706	    out_0 += output_ch;
1707	
